#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    char str[100];
    scanf("%s", str);
    int len = strlen(str);
    int* arr = (int*)malloc((len/2 + 1) * sizeof(int));
    int k = 0;
    for (int i = 0; i < len; i++) {
        if (str[i] != '+') {
            arr[k++] = str[i] - '0';
        }
    }
    qsort(arr, k, sizeof(int), compare);
    for (int i = 0; i < k; i++) {
        printf("%d", arr[i]);
    }
    return 0;
}

